DECLARE @Name_68ba6331 NVARCHAR(255),
@CategoryID_68ba6331 UNIQUEIDENTIFIER,
@UserQuestion_68ba6331 NVARCHAR(MAX),
@Description_68ba6331 NVARCHAR(MAX),
@SQL_68ba6331 NVARCHAR(MAX),
@TechnicalDescription_68ba6331 NVARCHAR(MAX),
@OriginalSQL_68ba6331 NVARCHAR(MAX),
@Feedback_68ba6331 NVARCHAR(MAX),
@Status_68ba6331 NVARCHAR(15),
@QualityRank_68ba6331 INT,
@ExecutionCostRank_68ba6331 INT,
@UsesTemplate_68ba6331 BIT,
@AuditQueryRuns_68ba6331 BIT,
@CacheEnabled_68ba6331 BIT,
@CacheTTLMinutes_68ba6331 INT,
@CacheMaxSize_68ba6331 INT,
@EmbeddingVector_68ba6331 NVARCHAR(MAX),
@EmbeddingModelID_68ba6331 UNIQUEIDENTIFIER,
@CacheValidationSQL_68ba6331 NVARCHAR(MAX),
@SQLDialectID_68ba6331 UNIQUEIDENTIFIER,
@Reusable_68ba6331 BIT,
@ID_68ba6331 UNIQUEIDENTIFIER
SET
  @Name_68ba6331 = N'ExternalChangeDetection_DetectCreations'
SET
  @CategoryID_68ba6331 = 'FE1AE5B2-FC57-43B2-B560-A673713E1679'
SET
  @Description_68ba6331 = N'Detects new records created in an external system by comparing base view rows to existing MJ record changes.'
SET
  @SQL_68ba6331 = N'-- T-SQL variant for External Change Detection - Detect Creations
SELECT
    ot.*, ot.[{{ CreatedAtField }}] AS __ecd_CreatedAt, ot.[{{ UpdatedAtField }}] AS __ecd_UpdatedAt
FROM
    [{{ SchemaName }}].[{{ BaseView }}] ot
LEFT JOIN
    ${flyway:defaultSchema}.vwRecordChanges rc
    ON
    ({{ PrimaryKeyJoin }} = rc.RecordID) AND
    rc.Type = ''Create'' AND
    rc.EntityID = {{ EntityID | sqlString }}
WHERE
    rc.RecordID IS NULL
ORDER BY
    {{ PrimaryKeyOrderBy }}
