SET
  @Name_6ef24cab = N'ExternalChangeDetection_DetectUpdates'
SET
  @CategoryID_6ef24cab = 'FE1AE5B2-FC57-43B2-B560-A673713E1679'
SET
  @Description_6ef24cab = N'Detects updated records in an external system by comparing UpdatedAt timestamps.'
SET
  @SQL_6ef24cab = N'-- T-SQL variant for External Change Detection - Detect Updates
SELECT
    ot.*, ot.[{{ UpdatedAtField }}] AS __ecd_UpdatedAt, rc.last_change_time __ecd_LatestRecordChangeAt
FROM
    [{{ SchemaName }}].[{{ BaseView }}] ot
INNER JOIN (
    SELECT
        RecordID, MAX(ChangedAt) AS last_change_time
    FROM
        ${flyway:defaultSchema}.vwRecordChanges
    WHERE
        Type IN (''Update'', ''Create'') AND EntityID = {{ EntityID | sqlString }}
    GROUP BY
        RecordID
) rc ON {{ PrimaryKeyJoin }} = rc.RecordID
WHERE
    ot.[{{ UpdatedAtField }}] > COALESCE(rc.last_change_time, ''1900-01-01 00:00:00.000'')
ORDER BY
    {{ PrimaryKeyOrderBy }}
'
